// C2: Acting Components
instance LiDARActuator : DTDFVocab:ActuatingComponent [
    base:desc "Remote management actuator for emergency braking commands in teleoperated ACC system via ROS2 control panel"
    base:isContainedIn PhysicalTwinEntity
]

instance SteeringServoActuator : DTDFVocab:ActuatingComponent [
    base:desc "Steering servo actuator for autonomous vehicle with low-latency communication requirements"
]

instance MotorActuator : DTDFVocab:ActuatingComponent [
    base:desc "Motor actuation component for autonomous vehicle with resource-constrained ECU offloading requirements"
]

// C3: Physical Sensing Components
instance LiDARSensor : DTDFVocab:SensingComponent [
    base:desc "1/10-scale autonomous vehicle LiDAR sensor collecting point cloud data for ACC system"
    DTDFVocab:producedData LiDARPointCloudData
]

instance VehicleStateSensor : DTDFVocab:SensingComponent [
    base:desc "Onboard vehicle state sensor providing speed, position, and heading data for ACC system"
    DTDFVocab:producedData VehicleStateData
]

instance SensorDataProcessingFE : DTDFVocab:SensingComponent [
    base:desc "Functional Entity processing raw sensor data into structured vehicle state information via ROS2 nodes"
    DTDFVocab:producedData PointCloudProcessingData
]

// C4: Data Transmitted
instance LiDARPointCloudData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom LiDARSensor
]

instance VehicleStateData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom VehicleStateSensor
]

instance PointCloudProcessingData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SensorDataProcessingFE
]

// C10: Models/Data
instance PointCloudClusteringModel : DTDFVocab:Model [
    base:desc "3D point cloud clustering and tracking model processing raw LiDAR data into object tracks for ACC system"
    DTDFVocab:inputTo PointCloudProcessingData
]

instance DataTranslationModel : DTDFVocab:Model [
    base:desc "ISO 23247 compliant data translation model converting sensor data units for inter-system communication"
    DTDFVocab:inputTo LiDARPointCloudData, VehicleStateData
]

instance ProjectedDrivingPathData : DTDFVocab:Data [
    base:desc "Generated projected driving path data for ACC system visualization and decision making"
    DTDFVocab:fromData PointCloudClusteringModel
    DTDFVocab:inputTo DataMonitoringService
]

instance ObjectTrackData : DTDFVocab:Data [
    base:desc "Structured object track data derived from point cloud processing for ACC system"
    DTDFVocab:fromData PointCloudProcessingData
    DTDFVocab:inputTo DataMonitoringService
]

instance VehicleStateDataProcessed : DTDFVocab:Data [
    base:desc "Processed vehicle state data with unit conversions for ACC system operations"
    DTDFVocab:fromData VehicleStateData
    DTDFVocab:inputTo ComputationOffloadingService
]

// C11: Enablers
instance ROS2CommunicationEnabler : DTDFVocab:Enabler [
    base:desc "ROS2-based communication framework enabling inter-node communication between functional entities and entities"
    DTDFVocab:enables DataMonitoringService, ComputationOffloadingService, RemoteManagementService
]

instance UDPWiFiCommunicationEnabler : DTDFVocab:Enabler [
    base:desc "UDP over Wi-Fi communication protocol for inter-entity communication between Physical Twin, Digital Twin, and User Entities"
    DTDFVocab:enables DataMonitoringService, RemoteManagementService
]

instance DataProcessingEnabler : DTDFVocab:Enabler [
    base:desc "Functional Entity processing framework handling sensor data processing and model execution"
    DTDFVocab:enables PointCloudClusteringModel, DataTranslationModel
]

instance VisualizationEnabler : DTDFVocab:Enabler [
    base:desc "3D visualization package for real-time vehicle state and object tracking display"
    DTDFVocab:enables DataMonitoringService
]

instance ControlPanelEnabler : DTDFVocab:Enabler [
    base:desc "ROS2-based control panel package for remote ACC management operations"
    DTDFVocab:enables RemoteManagementService
]

// C6: Services
instance DataMonitoringService : DTDFVocab:Service [
    base:desc "Real-time data monitoring service providing visualization of vehicle state, projected paths, and object tracks with data saving/report generation capabilities"
    DTDFVocab:provides DataVisualizationInsight, DataReportingAction
]

instance ComputationOffloadingService : DTDFVocab:Service [
    base:desc "Computation offloading service processing ACC system's lead vehicle detection, speed calculation, and actuation commands externally to alleviate on-board ECU constraints"
    DTDFVocab:provides LeadVehicleDetectionAction, SpeedCalculationAction, ActuationCommandAction
]

instance RemoteManagementService : DTDFVocab:Service [
    base:desc "Remote management service enabling operators to enable/disable ACC, set desired speeds, and issue emergency braking commands via UI"
    DTDFVocab:provides ACCOperationAction, SpeedSettingAction, EmergencyBrakingAction
]

// C17: Insights/Actions
instance DataVisualizationInsight : DTDFVocab:Insight [
    base:desc "Real-time visualization of vehicle state data, projected driving paths, and detected object tracks for operational monitoring"
]

instance DataReportingAction : DTDFVocab:Action [
    base:desc "Data saving and report generation functionality for post-operation analysis"
    DTDFVocab:IsAutomatic false
]

instance LeadVehicleDetectionAction : DTDFVocab:Action [
    base:desc "External processing of lead vehicle detection for ACC system computation offloading"
    DTDFVocab:IsAutomatic true
]

instance SpeedCalculationAction : DTDFVocab:Action [
    base:desc "Distance-based speed calculation for ACC system using projected paths and object tracks"
    DTDFVocab:IsAutomatic true
]

instance ActuationCommandAction : DTDFVocab:Action [
    base:desc "Remote actuation commands for vehicle speed control and emergency braking"
    DTDFVocab:IsAutomatic false
]

instance ACCOperationAction : DTDFVocab:Action [
    base:desc "Enable/disable ACC system operations via remote management interface"
    DTDFVocab:IsAutomatic false
]

instance SpeedSettingAction : DTDFVocab:Action [
    base:desc "Setting desired vehicle speed for ACC system via remote control panel"
    DTDFVocab:IsAutomatic false
]

instance EmergencyBrakingAction : DTDFVocab:Action [
    base:desc "Emergency braking command issuance for safety-critical operations"
    DTDFVocab:IsAutomatic false
]

// Entity Relationships
instance PhysicalTwinEntity : DTDFVocab:Environment [
    base:contains LiDARSensor, VehicleStateSensor, SensorDataProcessingFE, LiDARActuator, SteeringServoActuator, MotorActuator
]

instance DigitalTwinEntity : DTDFVocab:Environment [
    base:contains PointCloudClusteringModel, DataTranslationModel, ProjectedDrivingPathData, ObjectTrackData, DataMonitoringService, ComputationOffloadingService
]

instance UserEntityVisualization : DTDFVocab:Environment [
    base:contains VisualizationEnabler, DataMonitoringService
]

instance UserEntityControl : DTDFVocab:Environment [
    base:contains ControlPanelEnabler, RemoteManagementService
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "Control commands generated by the ACC Controlling FE, including motor and steering actuation signals, are serialized and translated via the ISO 23247 Data Translation FE. Commands are transmitted through ROS2 for internal software components and UDP over Wi-Fi for inter-entity communication to physical actuators."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Clock synchronization between physical and digital components is maintained at 100 ms accuracy due to hardware constraints, despite industry standards for safety-critical vehicular applications typically mandating stricter synchronization (e.g., <100 ms). This temporal granularity supports computation offloading and ensures coordinated device operation."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The Digital Twin architecture follows ISO 23247 Reference Architecture (RA), organizing components into Physical Twin, Digital Twin, and User Entities. Each Functional Entity (FE) is implemented as a ROS2 package with associated nodes. Notably, the Physical Twin Entity deviates from ISO 23247 by hosting general automotive functionality (e.g., Point Cloud Clustering & Tracking) rather than being limited to resource-specific operations as in the standard's OME. This structure ensures entity-specific deployment on distinct hardware while maintaining component integration via ROS2."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Communication between software components uses ROS2, while inter-entity communication occurs over Wi-Fi using UDP transport layer."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Compliance with ISO 23247 standard (Part 2: Reference Architecture), defining entity-based structure with Observable Manufacturing Elements (OME), Data Collection and Device Control Entity, Digital Twin Entity, and User Entity. Interoperability is achieved using OPC Unified Architecture for data collection and device control functions."
]
